package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private File mockFile;
    private CSVFormat mockFormat;
    private FileReader mockFileReader;

    @BeforeEach
    void setUp() throws Exception {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
        mockFileReader = mock(FileReader.class);
    }

    @Test
    void testParse_NullFile_ThrowsException() {
        CSVFormat format = mock(CSVFormat.class);
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, format);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void testParse_NullFormat_ThrowsException() {
        File file = mock(File.class);
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(file, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void testParse_ValidFileAndFormat_ReturnsCSVParser() throws IOException {
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class);
             MockedStatic<CSVParser> mockedCSVParser = Mockito.mockStatic(CSVParser.class)) {

            // Assertions.notNull does nothing (no exception)
            mockedAssertions.when(() -> Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            File file = mock(File.class);
            CSVFormat format = mock(CSVFormat.class);

            FileReader fileReader = mock(FileReader.class);
            // Spy on CSVParser constructor by mocking new CSVParser(FileReader, CSVFormat)
            // Since constructor cannot be mocked directly, we mock the new FileReader(file) call

            // Mock FileReader constructor call
            try (MockedStatic<FileReader> mockedFileReaderStatic = Mockito.mockStatic(FileReader.class)) {
                mockedFileReaderStatic.when(() -> new FileReader(file)).thenReturn(fileReader);

                CSVParser parser = new CSVParser(fileReader, format);
                // We expect parse to return new CSVParser(fileReader, format)
                CSVParser result = CSVParser.parse(file, format);
                assertNotNull(result);
                assertEquals(parser.getClass(), result.getClass());
            }
        }
    }
}
